            <div class='text-5xl font-bold text-red-600'>+40%</div>
            <div>
              <p class='font-semibold text-slate-900 text-lg'>Coinvolgimento studenti</p>
              <p class='text-slate-600'>Aumento partecipazione attiva nelle ore di laboratorio</p>
            </div>
          </div>
          <div class='flex items-center gap-6 p-6 bg-slate-50 rounded-xl'>
            <div class='text-5xl font-bold text-red-600'>12</div>
            <div>
              <p class='font-semibold text-slate-900 text-lg'>Scuole coinvolte</p>
              <p class='text-slate-600'>Licei artistici in 4 regioni italiane</p>
            </div>
          </div>
          <div class='flex items-center gap-6 p-6 bg-slate-50 rounded-xl'>
            <div class='text-5xl font-bold text-red-600'>500+</div>
            <div>
              <p class='font-semibold text-slate-900 text-lg'>Studenti formati</p>
              <p class='text-slate-600'>Nel primo anno di sperimentazione</p>
            </div>
          </div>
        </div>
        <div class='bg-gradient-to-br from-slate-900 to-slate-800 rounded-2xl p-8 text-white flex flex-col justify-center'>
          <i data-lucide='quote' class='w-12 h-12 text-red-500 mb-4'></i>
          <p class='text-2xl font-light italic leading-relaxed mb-6'>"MIDA non sostituisce il docente, ma amplifica la sua capacità di leggere il talento di ogni studente."</p>
          <p class='text-slate-400'>— Docente Liceo Artistico, Roma</p>
        </div>
      </div>
    </div>

    <!-- Slide 6: CTA -->
    <div class='slide slide-dark hidden' data-slide='6'>
      <div class='absolute top-0 left-0 w-full h-2 bg-tedx-red'></div>
      <div class='text-center max-w-4xl mx-auto'>
        <div class='accent-line mx-auto'></div>
        <h2 class='text-white text-5xl mb-6'>Il futuro è una tela condivisa</h2>
        <p class='text-xl text-slate-300 mb-12'>L'intelligenza artificiale non crea artisti.<br/>Gli artisti usano l'intelligenza artificiale per creare.</p>

        <div class='flex justify-center gap-6 mb-12'>
          <div class='bg-white/10 backdrop-blur px-8 py-4 rounded-full border border-white/20'>
            <p class='text-white font-semibold'>progettomida.it</p>
          </div>
          <div class='bg-white/10 backdrop-blur px-8 py-4 rounded-full border border-white/20'>
            <p class='text-white font-semibold'>@ProgettoMIDA</p>
          </div>
        </div>

        <div class='logo-tedx text-3xl'>TED<span>x</span></div>
        <p class='text-slate-500 mt-4'>Grazie</p>
      </div>
    </div>

  </div>

  <!-- Navigation Controls -->
  <div class='nav-controls'>
    <button class='nav-btn' onclick='prevSlide()' aria-label='Slide precedente'>
      <i data-lucide='chevron-left' class='w-6 h-6'></i>
    </button>
    <span class='slide-counter' id='slideCounter'>1 / 6</span>
    <button class='nav-btn' onclick='nextSlide()' aria-label='Slide successiva'>
      <i data-lucide='chevron-right' class='w-6 h-6'></i>
    </button>
  </div>

  <script>
    lucide.createIcons();

    let currentSlide = 1;
    const totalSlides = 6;

    function updateSlide() {
      document.querySelectorAll('.slide').forEach((slide, index) => {
        if (index + 1 === currentSlide) {
          slide.classList.remove('hidden');
          slide.classList.add('fade-in');
        } else {
          slide.classList.add('hidden');
          slide.classList.remove('fade-in');
        }
      });

      document.getElementById('slideCounter').textContent = currentSlide + ' / ' + totalSlides;
      document.getElementById('progressBar').style.width = (currentSlide / totalSlides * 100) + '%';
    }

    function nextSlide() {
      if (currentSlide < totalSlides) {
        currentSlide++;
        updateSlide();
      }
    }

    function prevSlide() {
      if (currentSlide > 1) {
        currentSlide--;
        updateSlide();
      }
    }

    document.addEventListener('keydown', (e) => {
      if (e.key === 'ArrowRight' || e.key === ' ') {
        e.preventDefault();
        nextSlide();
      } else if (e.key === 'ArrowLeft') {
        e.preventDefault();
        prevSlide();
      } else if (e.key === 'Home') {
        e.preventDefault();
        currentSlide = 1;
        updateSlide();
      } else if (e.key === 'End') {
        e.preventDefault();
        currentSlide = totalSlides;
        updateSlide();
      }
    });

    updateSlide();
  </script>
</body>
</html>",
